import React, { useState, useEffect } from 'react';
import { useProducts } from '../../hooks/useProducts';
import { Product } from '../../types/product';

const ProductForm: React.FC<{ productId?: string; onClose: () => void }> = ({ productId, onClose }) => {
    const { getProductById, createProduct, updateProduct } = useProducts();
    const [product, setProduct] = useState<Product | null>(null);
    const [name, setName] = useState('');
    const [price, setPrice] = useState(0);
    const [description, setDescription] = useState('');

    useEffect(() => {
        if (productId) {
            const fetchProduct = async () => {
                const fetchedProduct = await getProductById(productId);
                setProduct(fetchedProduct);
                if (fetchedProduct) {
                    setName(fetchedProduct.name);
                    setPrice(fetchedProduct.price);
                    setDescription(fetchedProduct.description);
                }
            };
            fetchProduct();
        }
    }, [productId, getProductById]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        const productData = { name, price, description };
        if (productId) {
            await updateProduct(productId, productData);
        } else {
            await createProduct(productData);
        }
        onClose();
    };

    return (
        <form onSubmit={handleSubmit}>
            <div>
                <label>Name:</label>
                <input
                    type="text"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    required
                />
            </div>
            <div>
                <label>Price:</label>
                <input
                    type="number"
                    value={price}
                    onChange={(e) => setPrice(Number(e.target.value))}
                    required
                />
            </div>
            <div>
                <label>Description:</label>
                <textarea
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    required
                />
            </div>
            <button type="submit">{productId ? 'Update Product' : 'Create Product'}</button>
        </form>
    );
};

export default ProductForm;
